import { CheckCircle, Clock, X, ChevronDown, ChevronUp, AlertCircle } from "lucide-react";
import type React from "react";
import { useState } from "react";
import { formatCurrency } from "../services/cartService";
import type { ActiveOrder } from "../types";
import "./CheckoutProgressSidebar.css";

interface CheckoutProgressSidebarProps {
	orders: ActiveOrder[];
	onDismissOrder: (requestId: string) => void;
	onClose: () => void;
}

const CheckoutProgressSidebar: React.FC<CheckoutProgressSidebarProps> = ({
	orders,
	onDismissOrder,
	onClose,
}) => {
	const [expandedOrders, setExpandedOrders] = useState<Set<string>>(new Set());

	const toggleOrderExpansion = (requestId: string) => {
		setExpandedOrders(prev => {
			const newSet = new Set(prev);
			if (newSet.has(requestId)) {
				newSet.delete(requestId);
			} else {
				newSet.add(requestId);
			}
			return newSet;
		});
	};

	const getStatusIcon = (status: ActiveOrder['status']) => {
		switch (status) {
			case 'processing':
				return <Clock size={16} className="text-blue-500" />;
			case 'completed':
				return <CheckCircle size={16} className="text-green-500" />;
			case 'failed':
				return <AlertCircle size={16} className="text-red-500" />;
			default:
				return <Clock size={16} className="text-gray-500" />;
		}
	};

	const getStatusColor = (status: ActiveOrder['status']) => {
		switch (status) {
			case 'processing':
				return '#3B82F6';
			case 'completed':
				return '#10B981';
			case 'failed':
				return '#EF4444';
			default:
				return '#6B7280';
		}
	};

	if (orders.length === 0) return null;

	return (
		<div className="checkout-progress-sidebar">
			<div className="sidebar-header">
				<h3 className="sidebar-title">
					Order Progress ({orders.length})
				</h3>
				<button
					type="button"
					className="close-sidebar-btn"
					onClick={onClose}
					aria-label="Close order progress"
				>
					<X size={20} />
				</button>
			</div>

			<div className="orders-list">
				{orders.map((order) => {
					const isExpanded = expandedOrders.has(order.requestId);
					return (
						<div key={order.requestId} className="order-card">
							<div 
								className="order-header"
								onClick={() => toggleOrderExpansion(order.requestId)}
								role="button"
								tabIndex={0}
								onKeyDown={(e) => {
									if (e.key === 'Enter' || e.key === ' ') {
										e.preventDefault();
										toggleOrderExpansion(order.requestId);
									}
								}}
							>
								<div className="order-info">
									<div className="order-status">
										{getStatusIcon(order.status)}
										<span className="order-id">
											{order.orderId || `Order #${order.requestId.slice(-6)}`}
										</span>
									</div>
									<div className="order-amount">
										{formatCurrency(order.totalAmount)}
									</div>
								</div>
								<div className="expand-icon">
									{isExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
								</div>
							</div>

							{order.status === 'processing' && (
								<div className="progress-container">
									<div className="progress-bar">
										<div 
											className="progress-fill"
											style={{ 
												width: `${order.progress}%`,
												backgroundColor: getStatusColor(order.status)
											}}
										/>
									</div>
									<div className="progress-text">
										{order.message} ({order.progress}%)
									</div>
								</div>
							)}

							{isExpanded && (
								<div className="order-details">
									<div className="detail-row">
										<span className="detail-label">Customer:</span>
										<span className="detail-value">{order.customerName}</span>
									</div>
									<div className="detail-row">
										<span className="detail-label">Started:</span>
										<span className="detail-value">
											{new Date(order.timestamp).toLocaleTimeString()}
										</span>
									</div>
									<div className="detail-row">
										<span className="detail-label">Items:</span>
										<span className="detail-value">{order.items.length} items</span>
									</div>
									{order.status !== 'processing' && (
										<button
											type="button"
											className="dismiss-btn"
											onClick={(e) => {
												e.stopPropagation();
												onDismissOrder(order.requestId);
											}}
										>
											Dismiss
										</button>
									)}
								</div>
							)}
						</div>
					);
				})}
			</div>
		</div>
	);
};

export default CheckoutProgressSidebar;