function App() {
	const [cartItems, setCartItems] = useState<CartItem[]>([]);
	const [showCheckout, setShowCheckout] = useState(false);
	const [showQRModal, setShowQRModal] = useState(false);
	const [userId] = useState<string>(() => {
		let id = localStorage.getItem("userId");
		if (!id) {
			id = uuidv4();
			localStorage.setItem("userId", id);
		}
		return id;
	});
	const [loading, setLoading] = useState(false);
	const { toasts, removeToast, showSuccess, showError } = useToast();
	
	// Track pending operations for optimistic updates
	const [pendingOps, setPendingOps] = useState<Set<string>>(new Set());
	
	// Track active orders for sidebar progress
	const [activeOrders, setActiveOrders] = useState<ActiveOrder[]>([]);
	const [showProgressSidebar, setShowProgressSidebar] = useState(false);

	const loadCart = useCallback(async () => {
		try {
			setLoading(true);
			const cart = await cartService.getCart(userId);
			setCartItems(cart.items || []);
		} catch (error) {
			console.error("Failed to load cart:", error);
			setCartItems([]);
		} finally {
			setLoading(false);
		}
	}, [userId]);

	// Load cart on component mount
	useEffect(() => {
		loadCart();
	}, [loadCart]);

	const addToCart = async (product: Product) => {
		const existingItem = cartItems.find(
			(item) => item.product_id === product.id,
		);

		// Optimistic update - show immediately
		let optimisticItems: CartItem[];
		if (existingItem) {
			optimisticItems = cartItems.map((item) =>
				item.product_id === product.id
					? { ...item, quantity: item.quantity + 1, pending: true }
					: item,
			);
		} else {
			const newItem: CartItem = {
				product_id: product.id,
				name: product.name,
				price: product.price,
				quantity: 1,
				image: product.image,
				pending: true,
			};
			optimisticItems = [...cartItems, newItem];
		}

		setCartItems(optimisticItems);
		setPendingOps(prev => new Set([...Array.from(prev), product.id]));

		try {
			// Prepare final items for API call (without pending flag)
			const finalItems = optimisticItems.map(item => ({
				...item,
				pending: undefined
			}));

			await cartService.updateCart(userId, finalItems);
			
			// Confirm optimistic update
			setCartItems(prev => prev.map(item => 
				item.product_id === product.id 
					? { ...item, pending: false }
					: item
			));
			showSuccess(`${product.name} added to cart!`);
		} catch (error) {
			console.error("Failed to add to cart:", error);
			// Rollback optimistic update
			if (existingItem) {
				setCartItems(prev => prev.map(item =>
					item.product_id === product.id
						? { ...item, quantity: item.quantity - 1, pending: false }
						: item
				));
			} else {
				setCartItems(prev => prev.filter(item => item.product_id !== product.id));
			}
			showError("Failed to add item to cart. Please try again.");
		} finally {
			setPendingOps(prev => {
				const newSet = new Set(prev);
				newSet.delete(product.id);
				return newSet;
			});
		}
	};

	const updateCartItem = async (productId: string, quantity: number) => {
		const originalItems = [...cartItems];
		
		// Optimistic update
		let optimisticItems: CartItem[];
		if (quantity <= 0) {
			optimisticItems = cartItems.filter(
				(item) => item.product_id !== productId,
			);
		} else {
			optimisticItems = cartItems.map((item) =>
				item.product_id === productId 
					? { ...item, quantity, pending: true }
					: item,
			);
		}

		setCartItems(optimisticItems);
		setPendingOps(prev => new Set([...Array.from(prev), productId]));

		try {
			// Prepare final items for API call (without pending flag)
			const finalItems = optimisticItems.map(item => ({
				...item,
				pending: undefined
			}));

			await cartService.updateCart(userId, finalItems);
			
			// Confirm optimistic update
			setCartItems(prev => prev.map(item => 
				item.product_id === productId 
					? { ...item, pending: false }
					: item
			));
			showSuccess("Cart updated successfully!");
		} catch (error) {
			console.error("Failed to update cart:", error);
			// Rollback to original state
			setCartItems(originalItems);
			showError("Failed to update cart. Please try again.");
		} finally {
			setPendingOps(prev => {
				const newSet = new Set(prev);
				newSet.delete(productId);
				return newSet;
			});
		}
	};

	const removeFromCart = async (productId: string) => {
		try {
			setLoading(true);
			const updatedItems = cartItems.filter(
				(item) => item.product_id !== productId,
			);
			await cartService.updateCart(userId, updatedItems);
			setCartItems(updatedItems);
			showSuccess("Item removed from cart!");
		} catch (error) {
			console.error("Failed to remove from cart:", error);
			showError("Failed to remove item from cart. Please try again.");
		} finally {
			setLoading(false);
		}
	};

	const clearCart = async () => {
		try {
			setLoading(true);
			await cartService.clearCart(userId);
			setCartItems([]);
			showSuccess("Cart cleared successfully!");
		} catch (error) {
			console.error("Failed to clear cart:", error);
			showError("Failed to clear cart. Please try again.");
		} finally {
			setLoading(false);
		}
	};

	const getTotalPrice = () => {
		return cartItems.reduce(
			(total, item) => total + item.price * item.quantity,
			0,
		);
	};

	// Add order to active tracking and start polling
	const handleOrderSubmitted = (requestId: string, customerName: string, totalAmount: number, items: CartItem[]) => {
		const newOrder: ActiveOrder = {
			requestId,
			customerName,
			totalAmount,
			status: 'processing',
			progress: 10,
			message: 'Submitting order...',
			timestamp: new Date().toISOString(),
			items
		};
		
		setActiveOrders(prev => [...prev, newOrder]);
		setShowProgressSidebar(true);
		setCartItems([]);
		setShowCheckout(false);
		
		// Start polling for this order
		pollOrderStatus(requestId);
	};

	// Poll order status and update progress
	const pollOrderStatus = async (requestId: string) => {
		const maxAttempts = 30; // 1 minute with 2-second intervals
		let attempts = 0;
		
		const poll = async () => {
			try {
				const statusData = await cartService.getCheckoutStatus(requestId);
				
				setActiveOrders(prev => prev.map(order => 
					order.requestId === requestId 
						? {
							...order,
							status: statusData.status === 'completed' ? 'completed' : 
									statusData.status === 'failed' ? 'failed' : 'processing',
							progress: statusData.progress,
							message: getStatusMessage(statusData.status, statusData.progress),
							orderId: statusData.orderId
						}
						: order
				));
				
				if (statusData.status === 'completed') {
					showSuccess('Order completed successfully!');
					return;
				}
				
				if (statusData.status === 'failed') {
					showError('Order processing failed');
					return;
				}
				
				attempts++;
				if (attempts < maxAttempts && statusData.status === 'processing') {
					setTimeout(poll, 2000);
				} else if (attempts >= maxAttempts) {
					setActiveOrders(prev => prev.map(order => 
						order.requestId === requestId 
							? { ...order, status: 'failed', message: 'Order processing timeout' }
							: order
					));
					showError('Order processing timeout');
				}
			} catch (error) {
				console.error('Status polling error:', error);
				if (attempts < maxAttempts) {
					setTimeout(poll, 2000);
				}
			}
		};
		
		poll();
	};

	// Helper function for status messages
	const getStatusMessage = (status: string, progress: number): string => {
		if (progress < 25) return 'Submitting order...';
		if (progress < 50) return 'Processing inventory...';
		if (progress < 75) return 'Authorizing payment...';
		if (progress < 90) return 'Preparing for fulfillment...';
		return 'Finalizing order...';
	};

	// Dismiss completed/failed orders
	const handleDismissOrder = (requestId: string) => {
		setActiveOrders(prev => prev.filter(order => order.requestId !== requestId));
		if (activeOrders.length <= 1) {
			setShowProgressSidebar(false);
		}
	};

	const handleCheckoutComplete = () => {
		setCartItems([]);
		setShowCheckout(false);
	};

	return (
		<div className="app">
			<header className="app-header">
				<div className="container">
					<button
						type="button"
						className="logo clickable-title"
						onClick={() => setShowQRModal(true)}
						onKeyDown={(e) => {
							if (e.key === "Enter" || e.key === " ") {
								e.preventDefault();
								setShowQRModal(true);
							}
						}}
						title="Click to share this page"
					>
						CNS203: Unicorn Dreams Store
					</button>
					<p className="tagline">Where Magic Meets Shopping</p>
				</div>
			</header>

			<main className="app-main">
				<div className="container">
					<div className="main-content">
						<div className="products-section">
							<h2>Magical Unicorn Collection</h2>
							<ProductGrid
								products={PRODUCTS}
								onAddToCart={addToCart}
								loading={loading}
							/>
						</div>

						<CartSidebar
							items={cartItems}
							onUpdateQuantity={updateCartItem}
							onRemoveItem={removeFromCart}
							onClearCart={clearCart}
							onCheckout={() => setShowCheckout(true)}
							totalPrice={getTotalPrice()}
							loading={loading}
						/>
					</div>
				</div>
			</main>

			{showCheckout && (
				<CheckoutModal
					items={cartItems}
					totalPrice={getTotalPrice()}
					userId={userId}
					onClose={() => setShowCheckout(false)}
					onCheckoutComplete={handleCheckoutComplete}
					onOrderSubmitted={handleOrderSubmitted}
					showError={showError}
				/>
			)}

			{showProgressSidebar && (
				<CheckoutProgressSidebar
					orders={activeOrders}
					onDismissOrder={handleDismissOrder}
					onClose={() => setShowProgressSidebar(false)}
				/>
			)}

			<QRCodeModal isOpen={showQRModal} onClose={() => setShowQRModal(false)} />

			<ToastContainer toasts={toasts} onRemoveToast={removeToast} />
		</div>
	);
}

export default App;
