import axios from "axios";
import type { Cart, CartItem, CheckoutRequest, CheckoutStatus } from "../types";

// Use relative API path - CloudFront will route /api/* to API Gateway
const API_BASE_URL = "/api";

const api = axios.create({
	baseURL: API_BASE_URL,
	headers: {
		"Content-Type": "application/json",
	},
});

export const cartService = {
	// Get user's cart
	async getCart(userId: string): Promise<Cart> {
		const response = await api.get("/cart", {
			headers: {
				"x-user-id": userId,
			},
		});
		return response.data;
	},

	// Create a new cart
	async createCart(userId: string, items: CartItem[] = []): Promise<Cart> {
		const response = await api.post(
			"/cart",
			{ items },
			{
				headers: {
					"x-user-id": userId,
				},
			},
		);
		return response.data;
	},

	// Update cart contents
	async updateCart(userId: string, items: CartItem[]): Promise<Cart> {
		const response = await api.put(
			"/cart",
			{ items },
			{
				headers: {
					"x-user-id": userId,
				},
			},
		);
		return response.data;
	},

	// Clear cart
	async clearCart(userId: string): Promise<void> {
		await api.delete("/cart", {
			headers: {
				"x-user-id": userId,
			},
		});
	},

	// Process checkout - returns requestId for status polling
	async checkout(checkoutData: CheckoutRequest): Promise<{ requestId: string }> {
		const response = await api.post("/checkout", checkoutData, {
			headers: {
				"x-user-id": checkoutData.user_id,
			},
		});
		return response.data;
	},

	// Get checkout status for polling
	async getCheckoutStatus(requestId: string): Promise<CheckoutStatus> {
		const response = await api.get(`/checkout/status/${requestId}`);
		return response.data;
	},
};

// Helper function to format currency
export const formatCurrency = (amount: number): string => {
	return new Intl.NumberFormat("en-US", {
		style: "currency",
		currency: "USD",
	}).format(amount);
};

// Helper function to calculate cart total
export const calculateCartTotal = (items: CartItem[]): number => {
	return items.reduce((total, item) => total + item.price * item.quantity, 0);
};